-- pgAdmin: mở Query Tool trên database analytics_db rồi chạy toàn bộ file này.
CREATE TABLE IF NOT EXISTS daily_platform_stats(stat_date date PRIMARY KEY,new_users int NOT NULL DEFAULT 0,total_views int NOT NULL DEFAULT 0,watch_minutes bigint NOT NULL DEFAULT 0,total_revenue numeric(14,2) NOT NULL DEFAULT 0,new_subscriptions int NOT NULL DEFAULT 0,cancelled_subscriptions int NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS content_performance(content_id varchar(40) PRIMARY KEY,title varchar(255) NOT NULL,view_count bigint NOT NULL DEFAULT 0,completion_rate numeric(5,2) NOT NULL DEFAULT 0,updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS admin_audit_logs(id bigserial PRIMARY KEY,admin_user_id varchar(40) NOT NULL,action varchar(80) NOT NULL,target_type varchar(50),target_id varchar(40),metadata jsonb NOT NULL DEFAULT '{}',created_at timestamptz NOT NULL DEFAULT now());
INSERT INTO daily_platform_stats SELECT d::date,(random()*18)::int,(500+random()*1200)::int,(8000+random()*15000)::int,(random()*4500000)::int,(random()*12)::int,(random()*3)::int FROM generate_series(current_date-13,current_date,interval '1 day') d ON CONFLICT DO NOTHING;
INSERT INTO content_performance VALUES('m-neon-delta','Neon Delta',18420,76.4,now()),('m-silent-bay','Vịnh Lặng Im',15310,68.2,now()),('m-seoul-after-midnight','Seoul Sau Nửa Đêm',14700,72.8,now()),('m-last-train','Chuyến Tàu Cuối',11090,81.1,now()) ON CONFLICT DO NOTHING;
